type Graph = Map<string, string[]>;

// BFS — shortest path (unweighted)
function bfsShortestPath(graph: Graph, start: string, end: string): string[] | null {
  const queue: string[][] = [[start]];
  const visited = new Set<string>([start]);
  while (queue.length > 0) {
    const path = queue.shift()!;
    const node = path[path.length - 1];
    if (node === end) return path;
    for (const neighbor of graph.get(node) ?? []) {
      if (!visited.has(neighbor)) {
        visited.add(neighbor);
        queue.push([...path, neighbor]);
      }
    }
  }
  return null;
}

// DFS — all reachable nodes
function dfsReachable(graph: Graph, start: string): string[] {
  const visited = new Set<string>();
  const result: string[] = [];
  function dfs(node: string) {
    if (visited.has(node)) return;
    visited.add(node);
    result.push(node);
    for (const neighbor of graph.get(node) ?? []) {
      dfs(neighbor);
    }
  }
  dfs(start);
  return result;
}

// Topological sort (Kahn's algorithm — BFS based)
function topologicalSort(graph: Graph): string[] | null {
  const inDegree = new Map<string, number>();
  for (const [node, neighbors] of graph) {
    if (!inDegree.has(node)) inDegree.set(node, 0);
    for (const n of neighbors) inDegree.set(n, (inDegree.get(n) ?? 0) + 1);
  }
  const queue = [...inDegree.entries()].filter(([, d]) => d === 0).map(([n]) => n);
  const order: string[] = [];
  while (queue.length) {
    const node = queue.shift()!;
    order.push(node);
    for (const neighbor of graph.get(node) ?? []) {
      const newDeg = (inDegree.get(neighbor) ?? 0) - 1;
      inDegree.set(neighbor, newDeg);
      if (newDeg === 0) queue.push(neighbor);
    }
  }
  return order.length === graph.size ? order : null; // null = cycle detected
}

