function findCycle(graph: Map<string, string[]>): string[] | null {
  const state = new Map<string, 'unvisited'|'active'|'done'>();
  const path: string[] = [];
  function dfs(node: string): boolean {
    state.set(node, 'active');
    path.push(node);
    for (const dep of graph.get(node) ?? []) {
      if (state.get(dep) === 'active') {
        const cycleStart = path.indexOf(dep);
        return true; // cycle from path[cycleStart..]
      }
      if (!state.has(dep) && dfs(dep)) return true;
    }
    path.pop();
    state.set(node, 'done');
    return false;
  }
  for (const node of graph.keys()) {
    if (!state.has(node) && dfs(node)) return path;
  }
  return null;
}

function countComponents(nodes: string[], edges: [string,string][]): number {
  const graph = new Map<string, string[]>();
  for (const n of nodes) graph.set(n, []);
  for (const [a,b] of edges) {
    graph.get(a)!.push(b);
    graph.get(b)!.push(a);
  }
  const visited = new Set<string>();
  let count = 0;
  for (const node of nodes) {
    if (!visited.has(node)) {
      count++;
      const queue = [node];
      while (queue.length) {
        const n = queue.shift()!;
        if (visited.has(n)) continue;
        visited.add(n);
        queue.push(...(graph.get(n) ?? []));
      }
    }
  }
  return count;
}
